def M (h k : ℕ) : ℕ := Nat.choose (h + k - 1) h
def K (h k : ℕ) : ℕ := Nat.choose (h + k - 1) k
def Delta (h k : ℕ) : Set ℤ := ⋃ ℓ ∈ Finset.range (min h k - 2), Icc (M h k + ℓ * h + 1) (M h k + ℓ * h + (h - 2 - ℓ))
